// TestProbeProtobufDump 直接测试 HandleProtobufMsg：
// 把 hexdump 还原成字节 → 按 JS 侧一样封装成 {"data": [byte...]} 的 payload
// → 调用 HandleProtobufMsg，打印它返回的 WechatMessage JSON 或错误。
func TestProbeProtobufDump(t *testing.T) {
	rawBytes := parseDump(t, dumpInput)
	t.Logf("解析出的字节数: %d", len(rawBytes))

	// 构造 HandleProtobufMsg 期望的 payload：data 是 []interface{}{float64,...}
	dataArr := make([]interface{}, len(rawBytes))
	for i, b := range rawBytes {
		dataArr[i] = float64(b)
	}
	payload := map[string]interface{}{"data": dataArr}

	jsonList, err := HandleProtobufMsg(payload)
	if err != nil {
		t.Fatalf("HandleProtobufMsg 失败: %v", err)
	}
	if len(jsonList) == 0 {
		t.Fatalf("HandleProtobufMsg 返回空（消息被全部跳过）")
	}

	fmt.Printf("========== HandleProtobufMsg 返回 %d 条消息 ==========\n", len(jsonList))
	for idx, jsonData := range jsonList {
		var pretty bytes.Buffer
		if err := json.Indent(&pretty, jsonData, "", "  "); err != nil {
			fmt.Printf("--- 消息 %d ---\n%s\n", idx, string(jsonData))
		} else {
			fmt.Printf("--- 消息 %d ---\n%s\n", idx, pretty.String())
		}
	}
}

// parseDump 从 hexdump 里抽出真正的字节。
// 针对 lldb / hexdump -C 的固定列宽格式：
//
//	地址(16 hex) + 2空格 + hex列(16字节) + 2空格 + ASCII列
//
// 第 0..17 字符是地址列，第 18 起是 hex 列（16 字节 = 48 字符宽，
// 中缝再占 1 空格）。按固定列宽切片，彻底避开 ASCII 列被误当字节。
func parseDump(t *testing.T, dump string) []byte {
	t.Helper()
	const addrCols = 18 // 16 hex 地址 + 2 空格
	const hexCols = 49  // 8字节*3 + 中缝1 + 8字节*3 = 49（含末尾空格，Fields 会忽略）
	var out []byte
	for _, line := range strings.Split(dump, "\n") {
		if strings.TrimSpace(line) == "" {
			continue
		}
		if len(line) <= addrCols {
			continue
		}
		end := addrCols + hexCols
		if end > len(line) {
			end = len(line)
		}
		for _, tk := range strings.Fields(line[addrCols:end]) {
			if len(tk) == 2 && isHexTok(tk) {
				var v int
				fmt.Sscanf(tk, "%02x", &v)
				out = append(out, byte(v))
			}
		}
	}
	return out
}

func isHexTok(s string) bool {
	for _, c := range s {
		if !((c >= '0' && c <= '9') || (c >= 'a' && c <= 'f') || (c >= 'A' && c <= 'F')) {
			return false
		}
	}
	return len(s) > 0
}
